import{_ as o,o as s,a as t,ag as i}from"./chunks/framework.1whTfjCw.js";const f=JSON.parse('{"title":"Profiles","description":"","frontmatter":{},"headers":[],"relativePath":"tnk/profiles.md","filePath":"tnk/profiles.md","lastUpdated":1784506044000}'),a={name:"tnk/profiles.md"};function n(r,e,l,d,c,p){return s(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="profiles" tabindex="-1">Profiles <a class="header-anchor" href="#profiles" aria-label="Permalink to &quot;Profiles&quot;">​</a></h1><p>Profiles define how sandbox environments are provisioned and constrained.</p><p><a href="https://github.com/tappunk/tnk-specs" target="_blank" rel="noreferrer">tappunk/tnk-specs</a> hosts sandbox profiles. <code>tnk init</code> clones this repository into <code>~/.config/tnk/</code>.</p><h2 id="common-profiles" tabindex="-1">Common profiles <a class="header-anchor" href="#common-profiles" aria-label="Permalink to &quot;Common profiles&quot;">​</a></h2><p>Resource values come from the YAML manifests in <code>~/.config/tnk/sandbox.d/manifests/</code>.</p><table tabindex="0"><thead><tr><th>Profile</th><th>CPUs</th><th>Memory</th><th>Best for</th></tr></thead><tbody><tr><td><code>base</code></td><td>1</td><td>2GiB</td><td><strong>Default</strong> — <code>tnk sandbox shell</code> without <code>--profile</code></td></tr><tr><td><code>pi</code></td><td>1</td><td>2GiB</td><td><strong>Default</strong> coding agent</td></tr></tbody></table><h3 id="what-each-profile-installs" tabindex="-1">What each profile installs <a class="header-anchor" href="#what-each-profile-installs" aria-label="Permalink to &quot;What each profile installs&quot;">​</a></h3><ul><li><strong><code>base</code></strong>: baseline resource allocation only (no provision script)</li><li><strong><code>pi</code></strong>: Node.js, <code>@earendil-works/pi-coding-agent</code>, fd, ripgrep</li></ul><h3 id="custom-profiles" tabindex="-1">Custom profiles <a class="header-anchor" href="#custom-profiles" aria-label="Permalink to &quot;Custom profiles&quot;">​</a></h3><p>Drop a shell script into <code>sandbox.d/provision.d/</code> and a matching YAML manifest into <code>sandbox.d/manifests/</code>. The script name (minus <code>.sh</code>) becomes your profile name. tnk discovers both automatically.</p><p>The YAML manifest supports:</p><ul><li><code>resources.cpus</code> / <code>resources.memory</code> — resource allocation</li><li><code>security.network</code> — <code>host</code> (default) or <code>restricted</code></li><li><code>mounts.workspace</code> — guest mount path (default <code>/workspace</code>)</li></ul><p>When you run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tnk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sandbox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> shell</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --profile</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>tnk will:</p><ol><li>ensure sandbox instance exists/runs</li><li>prepare baseline packages and user mapping</li><li>copy profile provision script + shared lib into sandbox</li><li>inject runtime env contract (<code>TNK_INFERENCE_URL</code>, <code>TNK_MODEL_NAME</code>, etc.)</li><li>execute provisioning script as sandbox user <code>tnk</code></li></ol><p>Provision state is fingerprinted so unchanged environments can skip expensive reinstall paths.</p><hr><p><strong>See also:</strong> <a href="/tnk/concepts">Concepts</a> · <a href="/tnk/sandbox">Sandbox</a> · <a href="/tnk/troubleshooting">Troubleshooting</a></p>',19)])])}const u=o(a,[["render",n]]);export{f as __pageData,u as default};
